def _parse_marker(source: str) -> str:
    for pattern in (
        r"@advanced_template\s+([A-Za-z0-9_\-]+)",
        r"@secure_template\s+([A-Za-z0-9_\-]+)",
        r"@contract_type\s+([A-Za-z0-9_\-]+)",
        r"@template\s+([A-Za-z0-9_\-]+)",
    ):
        match = re.search(pattern, source, re.IGNORECASE)
        if match:
            return match.group(1).strip().lower().replace("_", "-")
    return ""


def _fn(name: str, inputs: List[Tuple[str, str]] | None = None,
        outputs: List[Tuple[str, str]] | None = None,
        mutability: str = "nonpayable") -> Dict[str, Any]:
    return {
        "type": "function",
        "name": name,
        "inputs": [{"name": n, "type": t} for n, t in (inputs or [])],
        "outputs": [{"name": n, "type": t} for n, t in (outputs or [])],
        "stateMutability": mutability,
    }


def _event(name: str, inputs: List[Tuple[str, str, bool]]) -> Dict[str, Any]:
    return {
        "type": "event",
        "name": name,
        "inputs": [{"name": n, "type": t, "indexed": indexed} for n, t, indexed in inputs],
        "anonymous": False,
    }


def _common_abi() -> List[Dict[str, Any]]:
    return [
        {"type": "constructor", "inputs": [], "stateMutability": "nonpayable"},
        _fn("owner", outputs=[("", "address")], mutability="view"),
        _fn("pendingOwner", outputs=[("", "address")], mutability="view"),
        _fn("paused", outputs=[("", "bool")], mutability="view"),
        _fn("profileId", outputs=[("", "bytes32")], mutability="pure"),
        _fn("nonce", outputs=[("", "uint256")], mutability="view"),
        _fn("transferOwnership", [("newOwner", "address")], [("", "bool")]),
        _fn("acceptOwnership", outputs=[("", "bool")]),
        _fn("pause", outputs=[("", "bool")]),
        _fn("unpause", outputs=[("", "bool")]),
    ]


def _source(kind: str, name: str, body: str) -> str:
    marker = kind.upper().replace("-", "_")
    return f"// @advanced_template {marker}\ncontract {name} {{\n{body.rstrip()}\n}}\n"


