def detect_advanced_contract_kind(source: str) -> str:
    marker = _parse_marker(source)
    if marker in ALIASES:
        return ALIASES[marker]
    if marker:
        return ""
    lower = source.lower()
    tests = [
        ("safeTransferFrom".lower(), "erc1155-secure"),
        ("validatepaymasteruserop", "erc4337-verifying-paymaster"),
        ("validateuserop", "erc4337-smart-account"),
        ("clonedeterministic", "minimal-proxy-factory"),
        ("upgradeto", "transparent-proxy"),
        ("approveRelease".lower(), "bridge-vault"),
        ("swapexactin", "amm-constant-product"),
        ("notifyrewardamount", "staking-rewards"),
        ("escrowstate", "payment-escrow"),
        ("releasable", "token-vesting"),
        ("castvote", "governor-timelock"),
        ("delegate(", "governance-token"),
        ("submittransaction", "multisig-wallet"),
        ("converttoshares", "erc4626-vault"),
    ]
    for token, kind in tests:
        if token in lower:
            return kind
    return ""


def advanced_contract_template_catalog() -> List[Dict[str, Any]]:
    output: List[Dict[str, Any]] = []
    for kind, profile in _profiles().items():
        output.append({
            "kind": kind,
            "title": profile["title"],
            "category": profile["category"],
            "standard": profile["standard"],
            "risk": profile["risk"],
            "maturity": profile["maturity"],
            "description": profile["description"],
            "source": profile["source"],
        })
    return output


def _signature(item: Dict[str, Any]) -> str:
    return item["name"] + "(" + ",".join(arg["type"] for arg in item.get("inputs", [])) + ")"


def _require_owner(asm: _Assembler) -> None:
    asm.push(SLOT_OWNER).op("SLOAD").op("CALLER").op("EQ").op("ISZERO").push_label("revert").op("JUMPI")


def _require_not_paused(asm: _Assembler) -> None:
    asm.push(SLOT_PAUSED).op("SLOAD").push_label("revert").op("JUMPI")


def _require_address_at(asm: _Assembler, offset: int) -> None:
    _emit_revert_if_noncanonical_address_at(asm, offset)
    asm.push(offset).op("CALLDATALOAD").op("ISZERO").push_label("revert").op("JUMPI")


def _emit_return_void(asm: _Assembler) -> None:
    asm.push(0).push(0).op("RETURN")


def _emit_increment_nonce(asm: _Assembler) -> None:
    asm.push(SLOT_NONCE).op("SLOAD").push(1).op("ADD").op("DUP1").push(SLOT_NONCE).op("SSTORE")


def _emit_common_handlers(asm: _Assembler, profile_id: int, contract_name: str) -> None:
    asm.label("owner"); _emit_return_uint_slot(asm, SLOT_OWNER)
    asm.label("pendingOwner"); _emit_return_uint_slot(asm, SLOT_PENDING_OWNER)
    asm.label("paused"); _emit_return_uint_slot(asm, SLOT_PAUSED)
    asm.label("profileId"); _emit_return_uint_const(asm, profile_id)
    asm.label("nonce"); _emit_return_uint_slot(asm, SLOT_NONCE)
    asm.label("version"); _emit_return_string(asm, f"{contract_name} v1.0"[:32])

    asm.label("transferOwnership")
    _emit_revert_if_calldata_shorter_than(asm, 36); _require_owner(asm); _require_address_at(asm, 4)
    asm.push(4).op("CALLDATALOAD").push(SLOT_PENDING_OWNER).op("SSTORE")
    _emit_return_bool_true(asm)

    asm.label("acceptOwnership")
    asm.push(SLOT_PENDING_OWNER).op("SLOAD").op("CALLER").op("EQ").op("ISZERO").push_label("revert").op("JUMPI")
    asm.op("CALLER").push(SLOT_OWNER).op("SSTORE"); asm.push(0).push(SLOT_PENDING_OWNER).op("SSTORE")
    _emit_return_bool_true(asm)

    asm.label("pause"); _require_owner(asm); asm.push(1).push(SLOT_PAUSED).op("SSTORE"); _emit_return_bool_true(asm)
    asm.label("unpause"); _require_owner(asm); asm.push(0).push(SLOT_PAUSED).op("SSTORE"); _emit_return_bool_true(asm)


def _view_slot_for_name(name: str) -> int | None:
    mapping = {
        "implementation": SLOT_PRIMARY_ADDRESS,
        "admin": SLOT_OWNER,
        "entryPoint": SLOT_PRIMARY_ADDRESS,
        "recovery": SLOT_SECONDARY_ADDRESS,
        "verifyingSigner": SLOT_SECONDARY_ADDRESS,
        "assetToken": SLOT_PRIMARY_ADDRESS,
        "stakingToken": SLOT_PRIMARY_ADDRESS,
        "rewardToken": SLOT_SECONDARY_ADDRESS,
        "token": SLOT_PRIMARY_ADDRESS,
        "beneficiary": SLOT_SECONDARY_ADDRESS,
        "buyer": SLOT_OWNER,
        "seller": SLOT_PRIMARY_ADDRESS,
        "arbiter": SLOT_SECONDARY_ADDRESS,
        "asset": SLOT_PRIMARY_ADDRESS,
        "token0": SLOT_PRIMARY_ADDRESS,
        "token1": SLOT_SECONDARY_ADDRESS,
        "votingDelay": SLOT_PARAMETER_A,
        "votingPeriod": SLOT_PARAMETER_B,
        "quorum": SLOT_STATUS,
        "proposalCount": SLOT_COUNTER,
        "start": SLOT_PARAMETER_A,
        "duration": SLOT_PARAMETER_B,
        "released": SLOT_COUNTER,
        "amount": SLOT_PARAMETER_A,
        "escrowState": SLOT_STATUS,
        "totalStaked": SLOT_COUNTER,
        "reserve0": SLOT_PARAMETER_A,
        "reserve1": SLOT_PARAMETER_B,
        "totalLiquidity": SLOT_COUNTER,
        "validatorThreshold": SLOT_PARAMETER_A,
        "dailyLimit": SLOT_PARAMETER_B,
        "threshold": SLOT_PARAMETER_A,
        "totalAssets": SLOT_PARAMETER_A,
        "totalSupply": SLOT_COUNTER,
        "depositBalance": SLOT_COUNTER,
    }
    return mapping.get(name)


def _handler_label(signature: str) -> str:
    clean = re.sub(r"[^A-Za-z0-9_]", "_", signature)
    return "fn_" + clean


def _emit_view_handler(asm: _Assembler, item: Dict[str, Any], profile: Dict[str, Any]) -> bool:
    name = item["name"]
    outputs = item.get("outputs", [])
    if name in {"name", "symbol"}:
        asm.label(_handler_label(_signature(item)))
        _emit_return_string(asm, (profile["title"] if name == "name" else profile["kind"][:12]).strip()[:32])
        return True
    if name == "supportsInterface":
        asm.label(_handler_label(_signature(item))); _emit_return_uint_const(asm, 1); return True
    slot = _view_slot_for_name(name)
    if slot is not None and not item.get("inputs"):
        asm.label(_handler_label(_signature(item))); _emit_return_uint_slot(asm, slot); return True
    if name == "balanceOf" and len(item.get("inputs", [])) == 2:
        asm.label(_handler_label(_signature(item)))
        _emit_revert_if_calldata_shorter_than(asm, 68)
        asm.push(4).op("CALLDATALOAD"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES); asm.push(32).op("MSTORE")
        asm.push(36).op("CALLDATALOAD").push(0).op("MSTORE"); asm.push(64).push(0).op("SHA3")
        asm.op("SLOAD").push(0).op("MSTORE").push(32).push(0).op("RETURN")
        return True
    if name in {"balanceOf", "earned", "liquidityOf", "getVotes", "delegates", "isOwner", "isImplementationAllowed"}:
        asm.label(_handler_label(_signature(item)))
        _emit_revert_if_calldata_shorter_than(asm, 36)
        _emit_mapping_slot_from_calldata(asm, 4, MAPPING_BALANCES)
        asm.op("SLOAD").push(0).op("MSTORE").push(32).push(0).op("RETURN")
        return True
    if name == "processed":
        asm.label(_handler_label(_signature(item)))
        _emit_revert_if_calldata_shorter_than(asm, 36)
        _emit_mapping_slot_from_calldata(asm, 4, MAPPING_PROCESSED)
        asm.op("SLOAD").push(0).op("MSTORE").push(32).push(0).op("RETURN")
        return True
    if name in {"isApprovedForAll"}:
        asm.label(_handler_label(_signature(item)))
        _emit_revert_if_calldata_shorter_than(asm, 68)
        asm.push(4).op("CALLDATALOAD"); _emit_mapping_slot_from_stack_word(asm, MAPPING_APPROVALS); asm.push(32).op("MSTORE")
        asm.push(36).op("CALLDATALOAD").push(0).op("MSTORE"); asm.push(64).push(0).op("SHA3")
        asm.op("SLOAD").push(0).op("MSTORE").push(32).push(0).op("RETURN")
        return True
    if outputs:
        asm.label(_handler_label(_signature(item)))
        # Reference-core default: return zero words for all outputs.
        for index in range(len(outputs)):
            asm.push(0).push(index * 32).op("MSTORE")
        asm.push(max(32, len(outputs) * 32)).push(0).op("RETURN")
        return True
    return False


def _emit_state_handler(asm: _Assembler, item: Dict[str, Any], profile: Dict[str, Any]) -> None:
    signature = _signature(item)
    name = item["name"]
    asm.label(_handler_label(signature))
    minimum = 4 + 32 * len(item.get("inputs", []))
    # Dynamic tails are not decoded by the reference core, but fixed heads must exist.
    _emit_revert_if_calldata_shorter_than(asm, minimum)
    privileged = name in set(profile.get("privileged", []))
    if privileged:
        _require_owner(asm)
    if name not in {"unpause"}:
        _require_not_paused(asm)

    # Administrative setters update stable profile slots.
    if name in {"upgradeTo", "setEntryPoint", "setSigner"}:
        _require_address_at(asm, 4); asm.push(4).op("CALLDATALOAD").push(SLOT_PRIMARY_ADDRESS if name != "setSigner" else SLOT_SECONDARY_ADDRESS).op("SSTORE")
    elif name in {"changeAdmin", "setRecovery", "addOwner", "removeOwner", "setValidator", "setImplementationAllowed"}:
        _require_address_at(asm, 4)
        asm.push(4).op("CALLDATALOAD"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES)
        value_offset = 36 if len(item.get("inputs", [])) > 1 else None
        if name in {"removeOwner"}:
            asm.push(0)
        elif value_offset is not None:
            asm.push(value_offset).op("CALLDATALOAD")
        else:
            asm.push(1)
        asm.op("SWAP1").op("SSTORE")
    elif name in {"changeThreshold", "setThreshold", "setVotingDelay", "setVotingPeriod", "setQuorum", "setDailyLimit", "setFeeBps", "setUserLimit"}:
        asm.push(4).op("CALLDATALOAD").push(SLOT_PARAMETER_A).op("SSTORE")
    elif name == "setApprovalForAll":
        _require_address_at(asm, 4)
        asm.op("CALLER"); _emit_mapping_slot_from_stack_word(asm, MAPPING_APPROVALS); asm.push(32).op("MSTORE")
        asm.push(4).op("CALLDATALOAD").push(0).op("MSTORE"); asm.push(64).push(0).op("SHA3")
        asm.push(36).op("CALLDATALOAD").op("SWAP1").op("SSTORE")
    elif name in {"stake", "deposit", "fund", "lock"}:
        amount_offset = 4
        if name == "deposit" and len(item.get("inputs", [])) >= 2:
            receiver_offset = 36
            asm.push(receiver_offset).op("CALLDATALOAD")
        else:
            asm.op("CALLER")
        _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES)
        asm.op("DUP1").push(0x80).op("MSTORE").op("SLOAD")
        asm.push(amount_offset).op("CALLDATALOAD").op("ADD").push(0x80).op("MLOAD").op("SSTORE")
        asm.push(SLOT_COUNTER).op("SLOAD").push(amount_offset).op("CALLDATALOAD").op("ADD").push(SLOT_COUNTER).op("SSTORE")
    elif name in {"withdraw", "redeem"}:
        amount_offset = 4
        asm.op("CALLER"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES)
        asm.op("DUP1").push(0x80).op("MSTORE").op("SLOAD").op("DUP1").push(0xA0).op("MSTORE")
        asm.push(amount_offset).op("CALLDATALOAD").push(0xA0).op("MLOAD").op("LT").push_label("revert").op("JUMPI")
        asm.push(amount_offset).op("CALLDATALOAD").push(0xA0).op("MLOAD").op("SUB").push(0x80).op("MLOAD").op("SSTORE")
    elif name in {"propose", "submitTransaction", "cloneDeterministic", "lock"}:
        pass
    elif name in {"mint"} and profile["kind"] == "erc1155-secure":
        _require_owner(asm); _require_address_at(asm, 4)
        asm.push(4).op("CALLDATALOAD"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES); asm.push(32).op("MSTORE")
        asm.push(36).op("CALLDATALOAD").push(0).op("MSTORE"); asm.push(64).push(0).op("SHA3")
        asm.op("DUP1").push(0x80).op("MSTORE").op("SLOAD").push(68).op("CALLDATALOAD").op("ADD").push(0x80).op("MLOAD").op("SSTORE")
    elif name in {"safeTransferFrom", "burn"} and profile["kind"] == "erc1155-secure":
        from_offset = 4
        id_offset = 68 if name == "safeTransferFrom" else 36
        amount_offset = 100 if name == "safeTransferFrom" else 68
        asm.push(from_offset).op("CALLDATALOAD"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES); asm.push(32).op("MSTORE")
        asm.push(id_offset).op("CALLDATALOAD").push(0).op("MSTORE"); asm.push(64).push(0).op("SHA3")
        asm.op("DUP1").push(0x80).op("MSTORE").op("SLOAD").op("DUP1").push(0xA0).op("MSTORE")
        asm.push(amount_offset).op("CALLDATALOAD").push(0xA0).op("MLOAD").op("LT").push_label("revert").op("JUMPI")
        asm.push(amount_offset).op("CALLDATALOAD").push(0xA0).op("MLOAD").op("SUB").push(0x80).op("MLOAD").op("SSTORE")
        if name == "safeTransferFrom":
            _require_address_at(asm, 36)
            asm.push(36).op("CALLDATALOAD"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES); asm.push(32).op("MSTORE")
            asm.push(id_offset).op("CALLDATALOAD").push(0).op("MSTORE"); asm.push(64).push(0).op("SHA3")
            asm.op("DUP1").push(0xC0).op("MSTORE").op("SLOAD").push(amount_offset).op("CALLDATALOAD").op("ADD").push(0xC0).op("MLOAD").op("SSTORE")
    elif name in {"approveRelease", "release"} and profile["kind"] == "bridge-vault":
        # processed[messageId] = true on final release.
        if name == "release":
            _require_owner(asm)
            asm.push(4).op("CALLDATALOAD"); _emit_mapping_slot_from_stack_word(asm, MAPPING_PROCESSED)
            asm.op("DUP1").op("SLOAD").push_label("revert").op("JUMPI"); asm.push(1).op("SWAP1").op("SSTORE")
    elif name in {"delegate"}:
        _require_address_at(asm, 4)
        asm.op("CALLER"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES)
        asm.push(4).op("CALLDATALOAD").op("SWAP1").op("SSTORE")
    elif name in {"execute", "executeTransaction", "release", "refund", "resolve", "queue", "cancel", "getReward", "exit", "notifyRewardAmount", "addLiquidity", "removeLiquidity", "swapExactIn", "validateUserOp", "validatePaymasterUserOp", "postOp", "withdrawTo", "revoke", "approveTransaction", "revokeApproval"}:
        # Reference-core state progression and replay nonce.
        asm.push(SLOT_STATUS).op("SLOAD").push(1).op("ADD").push(SLOT_STATUS).op("SSTORE")

    _emit_increment_nonce(asm)
    outputs = item.get("outputs", [])
    if outputs:
        # Return nonce/action id for uint/address/bytes32 results, true for bool.
        if len(outputs) == 1 and outputs[0]["type"] == "bool":
            _emit_return_bool_true(asm)
        elif len(outputs) == 1:
            _emit_return_uint_slot(asm, SLOT_NONCE)
        else:
            for index in range(len(outputs)):
                asm.push(0).push(index * 32).op("MSTORE")
            asm.push(len(outputs) * 32).push(0).op("RETURN")
    else:
        _emit_return_void(asm)


def _runtime(profile: Dict[str, Any], contract_name: str) -> bytes:
    asm = _Assembler()
    # Deposit is the only payable function in this reference library.
    has_payable = any(item.get("stateMutability") == "payable" for item in profile["abi"] if item.get("type") == "function")
    if not has_payable:
        _emit_revert_if_callvalue(asm)
    _emit_revert_if_calldata_shorter_than(asm, 4)
    asm.push(0).op("CALLDATALOAD").push(224).op("SHR")

    common = [
        ("owner()", "owner"), ("pendingOwner()", "pendingOwner"), ("paused()", "paused"),
        ("profileId()", "profileId"), ("nonce()", "nonce"),
        ("transferOwnership(address)", "transferOwnership"), ("acceptOwnership()", "acceptOwnership"),
        ("pause()", "pause"), ("unpause()", "unpause"), ("version()", "version"),
    ]
    signatures = {sig for sig, _ in common}
    for signature, label in common:
        asm.op("DUP1").push(_selector(signature)).op("EQ").push_label(label).op("JUMPI")
    for item in profile["abi"]:
        if item.get("type") != "function":
            continue
        signature = _signature(item)
        if signature in signatures:
            continue
        signatures.add(signature)
        asm.op("DUP1").push(_selector(signature)).op("EQ").push_label(_handler_label(signature)).op("JUMPI")
    asm.op("POP"); _emit_revert(asm)

    profile_id = int(evm_keccak("AGILANG_PROFILE:" + profile["kind"]), 16)
    _emit_common_handlers(asm, profile_id, contract_name)

    for item in profile["abi"]:
        if item.get("type") != "function":
            continue
        signature = _signature(item)
        if signature in {sig for sig, _ in common}:
            continue
        if item.get("stateMutability") in {"view", "pure"}:
            if _emit_view_handler(asm, item, profile):
                continue
        _emit_state_handler(asm, item, profile)

    asm.label("revert"); _emit_revert(asm)
    return asm.finish()


def _parse_address(source: str, key: str, default: int) -> int:
    match = re.search(rf"\b{re.escape(key)}\s*=\s*(0x[0-9a-fA-F]{{40}})", source)
    if not match:
        return default
    return int(match.group(1), 16)


def _parse_uint(source: str, key: str, default: int) -> int:
    match = re.search(rf"\b{re.escape(key)}\s*=\s*([0-9]+)", source)
    return int(match.group(1)) if match else default


def _creation(runtime: bytes, source: str, kind: str) -> bytes:
    asm = _Assembler(); _emit_revert_if_callvalue(asm)
    asm.op("CALLER").push(SLOT_OWNER).op("SSTORE")
    asm.push(0).push(SLOT_PENDING_OWNER).op("SSTORE")
    asm.push(0).push(SLOT_PAUSED).op("SSTORE")

    primary = 0
    secondary = 0
    for key in ("assetToken", "stakingToken", "token", "asset", "token0", "entryPoint", "implementation"):
        value = _parse_address(source, key, 0)
        if value:
            primary = value; break
    for key in ("rewardToken", "beneficiary", "seller", "arbiter", "token1", "recovery", "verifyingSigner"):
        value = _parse_address(source, key, 0)
        if value:
            secondary = value; break
    asm.push(primary).push(SLOT_PRIMARY_ADDRESS).op("SSTORE")
    asm.push(secondary).push(SLOT_SECONDARY_ADDRESS).op("SSTORE")

    parameter_a = 0
    parameter_b = 0
    for key in ("votingDelay", "start", "amount", "validatorThreshold", "threshold", "reserve0"):
        value = _parse_uint(source, key, 0)
        if value:
            parameter_a = value; break
    for key in ("votingPeriod", "duration", "dailyLimit", "reserve1"):
        value = _parse_uint(source, key, 0)
        if value:
            parameter_b = value; break
    asm.push(parameter_a).push(SLOT_PARAMETER_A).op("SSTORE")
    asm.push(parameter_b).push(SLOT_PARAMETER_B).op("SSTORE")
    asm.push(0).push(SLOT_NONCE).op("SSTORE")
    asm.push(0).push(SLOT_STATUS).op("SSTORE")
    asm.push(0).push(SLOT_COUNTER).op("SSTORE")
    # Owner is registered in the generic owner/validator/implementation mapping.
    asm.op("CALLER"); _emit_mapping_slot_from_stack_word(asm, MAPPING_BALANCES); asm.push(1).op("SWAP1").op("SSTORE")
    return _emit_copy_runtime_return_prefix(runtime, bytearray(asm.finish()))


def compile_advanced_agilang_contract(source: str, *, chain_id: int, kind: str) -> Dict[str, Any]:
    profiles = _profiles()
    if kind not in profiles:
        raise AgilangContractCompileError(f"unsupported advanced contract kind: {kind}")
    profile = dict(profiles[kind])
    profile["kind"] = kind
    contract_name = _contract_name(source)
    runtime = _runtime(profile, contract_name)
    creation = _creation(runtime, source, kind)
    abi = profile["abi"]
    selectors: Dict[str, str] = {}
    events: Dict[str, str] = {}
    for item in abi:
        if item.get("type") == "function":
            signature = _signature(item)
            selectors[signature] = evm_function_selector(signature)
        elif item.get("type") == "event":
            signature = item["name"] + "(" + ",".join(arg["type"] for arg in item.get("inputs", [])) + ")"
            events[signature] = evm_keccak(signature)

    security = {
        "profile": "AGILANG-ADVANCED-CONTRACTS/1.0",
        "risk": profile["risk"],
        "maturity": profile["maturity"],
        "controls": profile["controls"],
        "privileged_functions": profile["privileged"],
        "warnings": profile["warnings"],
        "independent_audit": False,
        "mainnet_readiness": "audit-required" if profile["risk"] in {"advanced", "critical"} else "review-required",
        "reference_core": True,
    }
    return {
        "ok": True,
        "language": "AGILANG",
        "target": "evm",
        "chainId": int(chain_id),
        "contractName": contract_name,
        "contractKind": kind,
        "standard": profile["standard"],
        "compilerVersion": COMPILER_VERSION,
        "compiler": COMPILER_VERSION,
        "evmVersion": "shanghai",
        "optimization": False,
        "abi": abi,
        "bytecode": "0x" + creation.hex(),
        "runtimeBytecode": "0x" + runtime.hex(),
        "sourceCode": source,
        "generatedSource": f"// Generated by {COMPILER_VERSION}\n// {profile['standard']} reference core\ncontract {contract_name} {{ /* deterministic direct EVM implementation */ }}",
        "storageLayout": {
            "owner": SLOT_OWNER,
            "pendingOwner": SLOT_PENDING_OWNER,
            "paused": SLOT_PAUSED,
            "primaryAddress": SLOT_PRIMARY_ADDRESS,
            "secondaryAddress": SLOT_SECONDARY_ADDRESS,
            "parameterA": SLOT_PARAMETER_A,
            "parameterB": SLOT_PARAMETER_B,
            "nonce": SLOT_NONCE,
            "status": SLOT_STATUS,
            "counter": SLOT_COUNTER,
            "balances": MAPPING_BALANCES,
            "secondaryMapping": MAPPING_SECONDARY,
            "approvals": MAPPING_APPROVALS,
            "processed": MAPPING_PROCESSED,
        },
        "functionSelectors": selectors,
        "events": events,
        "security": security,
        "profile": {
            "title": profile["title"],
            "category": profile["category"],
            "maturity": profile["maturity"],
            "referenceCore": True,
        },
    }


__all__ = [
    "advanced_contract_template_catalog",
    "compile_advanced_agilang_contract",
    "detect_advanced_contract_kind",
]
